#!/bin/bash`n# bin/network.sh - 检测网络配置`n`nset -e`n`nSCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"`nPROJECT_DIR="$(cd "$SCRIPT_DIR/.." && pwd)"`n`nsource "$PROJECT_DIR/lib/output.sh"`n`nis_public_ip() {`n    local ip="$1"`n    local addr="${ip%%/*}"`n    `n    [[ "$addr" == 10.* ]] && return 1`n    [[ "$addr" == 172.1[6-9].* ]] || [[ "$addr" == 172.2[0-9].* ]] || [[ "$addr" == 172.3[0-1].* ]] && return 1`n    [[ "$addr" == 192.168.* ]] && return 1`n    [[ "$addr" == 127.* ]] && return 1`n    return 0`n}`n`nmain() {`n    header "网络检测"`n    `n    local eth=$(ip route | grep default | awk '{print $5}' | head -1)`n    eth="${eth:-eth0}"`n    `n    info "网络接口: $eth"`n    `n    local public_v4=""`n    local private_v4=""`n    local all_v4=$(ip -4 addr show "$eth" 2>/dev/null | grep -oP '(?<=inet\s)\d+(\.[0-9]+){3}/\d+' || echo "")`n    `n    for addr in $all_v4; do`n        if is_public_ip "$addr"; then`n            public_v4="$addr"`n        else`n            private_v4="$addr"`n        fi`n    done`n    `n    local public_v6=""`n    local all_v6=$(ip -6 addr show "$eth" 2>/dev/null | grep -oP '(?<=inet6\s)[a-f0-9:]+/\d+' || echo "")`n    `n    for addr in $all_v6; do`n        if [[ "$addr" != fe80:* ]]; then`n            public_v6="$addr"`n        fi`n    done`n    `n    local net_type="unknown"`n    if [[ -n "$public_v4" ]] && [[ -n "$public_v6" ]]; then`n        net_type="dual"`n    elif [[ -n "$public_v4" ]]; then`n        net_type="v4"`n    elif [[ -n "$public_v6" ]]; then`n        net_type="v6"`n    elif [[ -n "$private_v4" ]]; then`n        net_type="nat"`n    fi`n    `n    local gateway=$(ip -4 route show default 2>/dev/null | awk '{print $3}' | head -1)`n    `n    info "网络类型: $net_type"`n    info "公有 IPv4: ${public_v4:-无}"`n    info "私有 IPv4: ${private_v4:-无}"`n    info "IPv6: ${public_v6:-无}"`n    info "网关: ${gateway:-无}"`n    `n    echo ""`n    echo "NET_INTERFACE=$eth"`n    echo "NET_TYPE=$net_type"`n    echo "PUBLIC_V4=$public_v4"`n    echo "PRIVATE_V4=$private_v4"`n    echo "PUBLIC_V6=$public_v6"`n    echo "GATEWAY=$gateway"`n}`n`nmain "$@"`n